// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
bool solve(String rut) {
  final clean = rut.replaceAll(RegExp(r'[.\-\s]'), '').toUpperCase();
  if (clean.length < 2) return false;

  final body = clean.substring(0, clean.length - 1);
  final dv = clean.substring(clean.length - 1);

  if (!RegExp(r'^\d+\$').hasMatch(body)) return false;

  var sum = 0;
  var mul = 2;
  for (var i = body.length - 1; i >= 0; i--) {
    sum += int.parse(body[i]) * mul;
    mul = (mul == 7) ? 2 : (mul + 1);
  }

  final mod = 11 - (sum % 11);
  final dvCalc = (mod == 11) ? '0' : (mod == 10) ? 'K' : mod.toString();
  return dv == dvCalc;
}

