// C0650 · Leer/Escribir CSV (UTF-8) (Intermedio, IO)
import 'dart:io';

Future<void> solve() async {
  final input = File('input.csv');
  final lines = await input.readAsLines();
  if (lines.isEmpty) return;

  final headers = lines.first.split(',');
  final emailIdx = headers.indexOf('Email');

  final out = StringBuffer();
  out.writeln(lines.first);

  for (var i = 1; i < lines.length; i++) {
    final cols = lines[i].split(',');
    if (emailIdx >= 0 && emailIdx < cols.length) {
      cols[emailIdx] = cols[emailIdx].trim().toLowerCase();
    }
    out.writeln(cols.join(','));
  }
  await File('output.csv').writeAsString(out.toString());
}

