import 'dart:convert';
import 'package:http/http.dart' as http;

// pubspec.yaml: http: ^1.2.2
Future<Map<String, dynamic>> solve() async {
  final getRes = await http.get(Uri.parse('https://httpbin.org/get'));
  final getJson = jsonDecode(getRes.body);

  final postRes = await http.post(
    Uri.parse('https://httpbin.org/post'),
    headers: {'Content-Type': 'application/json'},
    body: jsonEncode({'hello': 'world'}),
  );
  final postJson = jsonDecode(postRes.body);

  return {'get': getJson, 'post': postJson};
}

