// C0661 · Retry + backoff + timeout (Intermedio, Resiliencia)
import 'dart:async';
import 'dart:math';

Future<void> solve({int maxRetries = 5}) async {
  var attempt = 0;
  var delay = Duration(milliseconds: 200);
  final rng = Random();
  while (true) {
    attempt++;
    if (rng.nextDouble() >= 0.7) return; // ok
    if (attempt >= maxRetries) throw Exception('fail');
    await Future.delayed(delay);
    final nextMs = (delay.inMilliseconds * 2).clamp(200, 5000);
    delay = Duration(milliseconds: nextMs);
  }
}

