// C0665 · Binary search (iterativo) (Básico, Algoritmos)
int solve(List<int> arr, int target) {
  var lo = 0;
  var hi = arr.length - 1;
  while (lo <= hi) {
    final mid = lo + ((hi - lo) >> 1);
    final v = arr[mid];
    if (v == target) return mid;
    if (v < target) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

