// C0666 · Merge sort (Intermedio, Algoritmos)
List<int> solve(List<int> arr) {
  if (arr.length <= 1) return arr;
  final mid = arr.length ~/ 2;
  final left = solve(arr.sublist(0, mid));
  final right = solve(arr.sublist(mid));
  final out = <int>[];
  var i = 0, j = 0;
  while (i < left.length && j < right.length) {
    if (left[i] <= right[j]) out.add(left[i++]);
    else out.add(right[j++]);
  }
  if (i < left.length) out.addAll(left.sublist(i));
  if (j < right.length) out.addAll(right.sublist(j));
  return out;
}

