// C0667 · BFS/DFS (grafo) (Intermedio, Algoritmos)
List<int> bfs(List<List<int>> g, int start) {
  final q = <int>[start];
  var head = 0;
  final seen = List<bool>.filled(g.length, false);
  final out = <int>[];
  seen[start] = true;

  while (head < q.length) {
    final v = q[head++];
    out.add(v);
    for (final nb in g[v]) {
      if (!seen[nb]) { seen[nb] = true; q.add(nb); }
    }
  }
  return out;
}

List<int> dfs(List<List<int>> g, int start) {
  final seen = List<bool>.filled(g.length, false);
  final out = <int>[];
  void visit(int v) {
    seen[v] = true;
    out.add(v);
    for (final nb in g[v]) {
      if (!seen[nb]) visit(nb);
    }
  }
  visit(start);
  return out;
}

