// C0668 · A* (pathfinding) (Avanzado, Algoritmos)
List<List<int>> solve(List<List<int>> grid, List<int> start, List<int> goal) {
  final h = grid.length;
  final w = grid[0].length;
  int hcost(List<int> a, List<int> b) => (a[0]-b[0]).abs() + (a[1]-b[1]).abs();
  String key(List<int> p) => "${p[0]},${p[1]}";

  List<List<int>> neighbors(List<int> p) {
    final x=p[0], y=p[1];
    final out = <List<int>>[];
    const dirs = [[1,0],[-1,0],[0,1],[0,-1]];
    for (final d in dirs) {
      final nx=x+d[0], ny=y+d[1];
      if (nx>=0 && ny>=0 && nx<w && ny<h && grid[ny][nx]==0) out.add([nx,ny]);
    }
    return out;
  }

  final open = <List<dynamic>>[[hcost(start,goal), start]];
  final came = <String, List<int>>{};
  final g = <String, int>{ key(start): 0 };

  while (open.isNotEmpty) {
    open.sort((a,b)=> (a[0] as int).compareTo(b[0] as int));
    final cur = open.removeAt(0)[1] as List<int>;
    if (cur[0]==goal[0] && cur[1]==goal[1]) {
      final path = <List<int>>[cur];
      var ck = key(cur);
      var c = cur;
      while (came.containsKey(ck)) {
        c = came[ck]!;
        path.add(c);
        ck = key(c);
      }
      return path.reversed.toList();
    }
    for (final nb in neighbors(cur)) {
      final nk = key(nb);
      final ng = g[key(cur)]! + 1;
      if (!g.containsKey(nk) || ng < g[nk]!) {
        g[nk] = ng;
        came[nk] = cur;
        open.add([ng + hcost(nb,goal), nb]);
      }
    }
  }
  return [];
}

