// C0669 · LRU cache (Intermedio, Algoritmos)
class LRU<K, V> {
  final int cap;
  final _map = <K, V>{}; // insertion-ordered
  LRU(this.cap);

  V? get(K k) {
    if (!_map.containsKey(k)) return null;
    final v = _map.remove(k)!;
    _map[k] = v;
    return v;
  }

  void put(K k, V v) {
    _map.remove(k);
    _map[k] = v;
    if (_map.length > cap) {
      final oldest = _map.keys.first;
      _map.remove(oldest);
    }
  }
}

