// C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
// Dart: stdin (requiere Enter)
import 'dart:io';

void solve() {
  stdout.writeln('Escribe una tecla y Enter (w/a/s/d, q):');
  while (true) {
    final line = stdin.readLineSync();
    if (line == null || line.isEmpty) continue;
    final k = line[0].toLowerCase();
    if (k == 'q') break;
    if (k == 'w') stdout.writeln('Mover: arriba');
    if (k == 's') stdout.writeln('Mover: abajo');
    if (k == 'a') stdout.writeln('Mover: izquierda');
    if (k == 'd') stdout.writeln('Mover: derecha');
  }
}

